namespace sv_58e2a5de63aa4129898c90f29b80d425.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@using sv_58e2a5de63aa4129898c90f29b80d425.Models

<div class="settings-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_profile is null)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="text-center">
                    <label class="form-label fw-semibold d-block">Avatar Preview</label>
                    <div class="avatar-preview mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width:120px;height:120px;object-fit:cover;" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                                 style="width:120px;height:120px;margin:0 auto;">
                                <span class="text-white fs-1">@(_displayName?.FirstOrDefault())</span>
                            </div>
                        }
                    </div>
                    <small class="text-muted text-break">@_avatarUrl</small>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mt-4 d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private string? _message;
    private bool _isError;
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        ApplyProfile(_profile);
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _message = "Profile saved successfully!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            ApplyProfile(_profile);
        }
        _message = null;
    }
}

@using sv_58e2a5de63aa4129898c90f29b80d425.Models

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_prefs is null)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">General</h6>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="emailNotif">
                        Email Notifications
                    </label>
                    <div class="form-text">Receive notifications via email</div>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="pushNotif">
                        Push Notifications
                    </label>
                    <div class="form-text">Receive browser push notifications</div>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="weeklyDigest">
                        Weekly Digest
                    </label>
                    <div class="form-text">Receive a weekly summary of activity</div>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                @if (_channels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _channels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                @channel <span class="badge bg-secondary ms-1">muted</span>
                            </label>
                        </div>
                    }
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    // All known channels — in a real app this would come from a service
    private List<string> _channels = new();
    private string? _message;
    private bool _isError;
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
        // Populate channel list from muted channels so there's something to display
        _channels = _prefs.MutedChannels.ToList();
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications, _pushNotifications, _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _message = "Notification preferences saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_58e2a5de63aa4129898c90f29b80d425.Models

<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_settings is null)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor:pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span class="fw-semibold">Change Password</span>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="alert @(_passwordIsError ? "alert-danger" : "alert-success") py-2" role="alert">
                            @_passwordMessage
                        </div>
                    }

                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (_settings.LastPasswordChange.HasValue)
                    {
                        <div class="form-text mt-1">
                            Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                        </div>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
