                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (!string.IsNullOrEmpty(_revokeMessage))
        {
            <div class="alert @(_revokeIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_revokeMessage
                <button type="button" class="btn-close" @onclick="() => _revokeMessage = null"></button>
            </div>
