                        <tbody>
                            @foreach (var session in _settings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (session == _settings.Sessions.FirstOrDefault())
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal d-block fade show" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted mb-0">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (!string.IsNullOrEmpty(_revokeMessage))
        {
            <div class="alert @(_revokeIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_revokeMessage
                <button type="button" class="btn-close" @onclick="() => _revokeMessage = null"></button>
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? _settings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordMessage;
    private bool _passwordIsError;
    private bool _changingPassword;

    private bool _twoFactorEnabled;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private string? _revokeMessage;
    private bool _revokeIsError;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "New password cannot be empty.";
            _passwordIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully!";
            _passwordIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Failed to change password: {ex.Message}";
            _passwordIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        _revokeMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _revokeMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _revokeIsError = false;
            // Reload sessions
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _revokeMessage = $"Failed to revoke session: {ex.Message}";
            _revokeIsError = true;
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}

