                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _settings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (session == _settings.Sessions.FirstOrDefault())
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal d-block fade show" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted mb-0">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (!string.IsNullOrEmpty(_revokeMessage))
        {
            <div class="alert @(_revokeIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_revokeMessage
                <button type="button" class="btn-close" @onclick="() => _revokeMessage = null"></button>
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? _settings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordMessage;
    private bool _passwordIsError;
    private bool _changingPassword;

    private bool _twoFactorEnabled;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private string? _revokeMessage;
    private bool _revokeIsError;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "New password cannot be empty.";
            _passwordIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully!";
            _passwordIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Failed to change password: {ex.Message}";
            _passwordIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        _revokeMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _revokeMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _revokeIsError = false;
            // Reload sessions
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _revokeMessage = $"Failed to revoke session: {ex.Message}";
            _revokeIsError = true;
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}
"}

{"path": "/tmp/sv-58e2a5de63aa4129898c90f29b80d425/Components/Pages/Settings/AppearanceSection.razor", "file_text": "@using sv_58e2a5de63aa4129898c90f29b80d425.Models

<div class="settings-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_settings is null)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                @* Theme *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* Font Size *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* Language *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                @* Compact Mode *@
                <div class="card mb-4">
                    <div class="card-body d-flex justify-content-between align-items-center">
                        <div>
                            <h6 class="mb-1">Compact Mode</h6>
                            <small class="text-muted">Reduce spacing and padding throughout the interface</small>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </div>
                </div>
            </div>

            @* Live Preview *@
            <div class="col-md-5">
                <div class="card sticky-top" style="top:1rem;">
                    <div class="card-header fw-semibold">Live Preview</div>
                    <div class="card-body @PreviewThemeClass()" style="@PreviewStyle(); transition: all 0.3s ease;">
                        <h6 style="@PreviewFontStyle()">Sample Heading</h6>
                        <p style="@PreviewFontStyle()" class="@(_compactMode ? "mb-1" : "mb-3")">
                            This is a preview of how your content will look with the selected settings.
                        </p>
                        <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                            <button class="btn btn-sm btn-primary">Primary</button>
                            <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                        </div>
                        <div class="@(_compactMode ? "p-1" : "p-2") border rounded" style="@PreviewFontStyle()">
                            <small class="text-muted d-block">Language: @_language</small>
                            <small class="text-muted d-block">Theme: @_theme</small>
                            <small class="text-muted d-block">Font: @_fontSize</small>
                            <small class="text-muted d-block">Compact: @(_compactMode ? "On" : "Off")</small>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-2" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private AppearanceSettings? _settings;
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private string? _message;
    private bool _isError;
    private bool _saving;

    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetAppearanceAsync();
        _theme = _settings.Theme;
        _fontSize = _settings.FontSize;
        _language = _settings.Language;
        _compactMode = _settings.CompactMode;
    }

    private string PreviewThemeClass() => _theme switch
    {
        "Dark" => "bg-dark text-light",
        _ => "bg-white text-dark"
    };

    private string PreviewStyle() => _theme switch
    {
        "Dark" => "border-color: #495057 !important;",
        _ => ""
    };

    private string PreviewFontStyle() => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _settings = updated;
            _message = "Appearance settings saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save settings: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

