@using sv_58e2a5de63aa4129898c90f29b80d425.Models

<div class="settings-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_prefs is null)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">General</h6>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="emailNotif">
                        Email Notifications
                    </label>
                    <div class="form-text">Receive notifications via email</div>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="pushNotif">
                        Push Notifications
                    </label>
                    <div class="form-text">Receive browser push notifications</div>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="weeklyDigest">
                        Weekly Digest
                    </label>
                    <div class="form-text">Receive a weekly summary of activity</div>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                @if (_channels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _channels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                @channel <span class="badge bg-secondary ms-1">muted</span>
                            </label>
                        </div>
                    }
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    // All known channels — in a real app this would come from a service
    private List<string> _channels = new();
    private string? _message;
    private bool _isError;
    private bool _saving;

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
        // Populate channel list from muted channels so there's something to display
        _channels = _prefs.MutedChannels.ToList();
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new NotificationPrefs(
                _emailNotifications, _pushNotifications, _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _message = "Notification preferences saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save preferences: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

