@using sv_58e2a5de63aa4129898c90f29b80d425.Models

<div class="settings-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_settings is null)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor:pointer;" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span class="fw-semibold">Change Password</span>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (!string.IsNullOrEmpty(_passwordMessage))
                    {
                        <div class="alert @(_passwordIsError ? "alert-danger" : "alert-success") py-2" role="alert">
                            @_passwordMessage
                        </div>
                    }

                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    @if (_settings.LastPasswordChange.HasValue)
                    {
                        <div class="form-text mt-1">
                            Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                        </div>
                    }
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="twoFactor"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header fw-semibold">Active Sessions</div>
            <div class="card-body p-0">
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead class="table-light">
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th class="text-end">Action</th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _settings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td class="text-end">
                                        @if (session == _settings.Sessions.FirstOrDefault())
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                        else
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal d-block fade show" tabindex="-1" role="dialog">
                <div class="modal-dialog modal-dialog-centered" role="document">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted mb-0">This will sign out the device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (!string.IsNullOrEmpty(_revokeMessage))
        {
            <div class="alert @(_revokeIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_revokeMessage
                <button type="button" class="btn-close" @onclick="() => _revokeMessage = null"></button>
            </div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private SecuritySettings? _settings;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordMessage;
    private bool _passwordIsError;
    private bool _changingPassword;

    private bool _twoFactorEnabled;

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private string? _revokeMessage;
    private bool _revokeIsError;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordMessage = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordMessage = "New password cannot be empty.";
            _passwordIsError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _passwordMessage = "New password and confirmation do not match.";
            _passwordIsError = true;
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordMessage = "Password updated successfully!";
            _passwordIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordMessage = $"Failed to change password: {ex.Message}";
            _passwordIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        _revokeMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _revokeMessage = $"Session on {_sessionToRevoke.Device} has been revoked.";
            _revokeIsError = false;
            // Reload sessions
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _revokeMessage = $"Failed to revoke session: {ex.Message}";
            _revokeIsError = true;
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}

