arguments.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_58e2a5de63aa4129898c90f29b80d425.Models
@using sv_58e2a5de63aa4129898c90f29b80d425.Components.Pages.Settings
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-sidebar">
        <nav class="nav flex-column">
            @foreach (var section in _sections)
            {
                <button class="nav-link settings-nav-link @(section == _activeSection ? "active" : "")"
                        @onclick="() => _activeSection = section">
                    <span class="settings-nav-icon">@SectionIcon(section)</span>
                    @section
                </button>
            }
        </nav>
    </div>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection SettingsService="SettingsService" />
                break;
            case "Notifications":
                <NotificationsSection SettingsService="SettingsService" />
                break;
            case "Security":
                <SecuritySection SettingsService="SettingsService" />
                break;
            case "Appearance":
                <AppearanceSection SettingsService="SettingsService" />
                break;
        }
    </div>
</div>

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    private static string SectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-dashboard {
    display: flex;
    gap: 1.5rem;
    min-height: 70vh;
}

.settings-sidebar {
    min-width: 200px;
    max-width: 220px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-nav-link {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.65rem 1rem;
    margin-bottom: 0.25rem;
    border-radius: 0.5rem;
    border: none;
    background: transparent;
    color: #495057;
    font-weight: 500;
    cursor: pointer;
    text-align: left;
    width: 100%;
    transition: background-color 0.15s, color 0.15s;
}

.settings-nav-link:hover {
    background-color: #f0f0f0;
    color: #212529;
}

.settings-nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

.settings-nav-link.active:hover {
    background-color: #0b5ed7;
}

.settings-nav-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

